<?php
namespace Tests\Feature;
use App\Domain\Wallet\GoldReasonCode;use App\Domain\Wallet\WalletService;use App\Models\Character;use App\Models\User;use Database\Seeders\CharacterLevelRequirementSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class CharacterWalletTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(CharacterLevelRequirementSeeder::class);}public function test_authorization_and_view(){$u=User::factory()->create();$c=Character::factory()->for($u)->create();$this->get(route('characters.wallet.show',$c))->assertRedirect('/login');$this->actingAs(User::factory()->create())->get(route('characters.wallet.show',$c))->assertForbidden();$this->actingAs($u)->get(route('characters.wallet.show',$c))->assertOk()->assertSee('Todavía no existen movimientos');app(WalletService::class)->credit($c,75,GoldReasonCode::ADMIN_GRANT,'Prueba');$this->get(route('characters.wallet.show',$c))->assertOk()->assertSee('75 oro')->assertSee('Prueba');$this->get(route('characters.show',$c))->assertSee(route('characters.wallet.show',$c));}}
